9	// ─── initDb / closeDb ─────────────────────────────────────────────────────────
10	describe('initDb / closeDb', () => {
11	  it('initDb(:memory:) returns a Database instance', () => {
12	    const db = initDb(':memory:');
13	    assert.ok(db, 'should return a truthy db');
14	    closeDb();
15	  });
16	
17	  it('creates cards table', () => {
18	    const db = initDb(':memory:');
19	    const row = db.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='cards'").get();
20	    assert.ok(row, 'cards table should exist');
21	    closeDb();
22	  });
23	
24	  it('creates comments table', () => {
25	    const db = initDb(':memory:');
26	    const row = db.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='comments'").get();
27	    assert.ok(row, 'comments table should exist');
28	    closeDb();
29	  });
30	
31	  it('enables foreign keys (pragma returns 1)', () => {
32	    const db = initDb(':memory:');
33	    const val = db.pragma('foreign_keys', { simple: true });
34	    assert.equal(val, 1);
35	    closeDb();
36	  });
37	
38	  it('closeDb() closes the database (subsequent prepare() throws)', () => {
39	    const db = initDb(':memory:');
40	    closeDb();
41	    assert.throws(() => db.prepare('SELECT 1'), /database|connection/i);
42	  });
43	
44	  it('can call initDb again after closeDb', () => {
45	    initDb(':memory:');
46	    closeDb();
47	    const db2 = initDb(':memory:');
48	    assert.ok(db2);
49	    closeDb();
50	  });
51	});
