53	// ─── getCards ─────────────────────────────────────────────────────────────────
54	describe('getCards', () => {
55	  beforeEach(() => initDb(':memory:'));
56	  afterEach(() => closeDb());
57	
58	  it('returns empty array when no cards', () => {
59	    assert.deepEqual(getCards(), []);
60	  });
61	
62	  it('returns cards with empty comments array', () => {
63	    createCard({ title: 'Card A' });
64	    const cards = getCards();
65	    assert.equal(cards.length, 1);
66	    assert.deepEqual(cards[0].comments, []);
67	  });
68	
69	  it('returns cards ordered by column then position', () => {
70	    createCard({ title: 'R1', column: 'ready' });
71	    createCard({ title: 'D1', column: 'done' });
72	    createCard({ title: 'R2', column: 'ready' });
73	    createCard({ title: 'I1', column: 'in_progress' });
74	    const cards = getCards();
75	    // ORDER BY "column", position — alphabetical by column name
76	    // 'done' < 'in_progress' < 'ready'
77	    const titles = cards.map(c => c.title);
78	    assert.equal(titles[0], 'D1');
79	    assert.equal(titles[1], 'I1');
80	    assert.equal(titles[2], 'R1');
81	    assert.equal(titles[3], 'R2');
82	  });
83	
84	  it('nests comments under the correct card', () => {
85	    const card1 = createCard({ title: 'Card 1' });
86	    const card2 = createCard({ title: 'Card 2' });
87	    createComment(card1.id, { author: 'Alice', content: 'Hello from card 1' });
88	    createComment(card2.id, { author: 'Bob',   content: 'Hello from card 2' });
89	    const cards = getCards();
90	    const c1 = cards.find(c => c.id === card1.id);
91	    const c2 = cards.find(c => c.id === card2.id);
92	    assert.equal(c1.comments.length, 1);
93	    assert.equal(c1.comments[0].content, 'Hello from card 1');
94	    assert.equal(c2.comments.length, 1);
95	    assert.equal(c2.comments[0].content, 'Hello from card 2');
96	  });
97	
98	  it('comments are ordered by created_at within a card', () => {
99	    const card = createCard({ title: 'Card' });
100	    createComment(card.id, { author: 'A', content: 'First'  });
101	    createComment(card.id, { author: 'B', content: 'Second' });
102	    const cards = getCards();
103	    const comments = cards[0].comments;
104	    assert.equal(comments.length, 2);
105	    assert.ok(comments[0].created_at <= comments[1].created_at);
106	    assert.equal(comments[0].content, 'First');
107	    assert.equal(comments[1].content, 'Second');
108	  });
109	});
