111	// ─── createCard ───────────────────────────────────────────────────────────────
112	describe('createCard', () => {
113	  beforeEach(() => initDb(':memory:'));
114	  afterEach(() => closeDb());
115	
116	  it('returns card with all required fields', () => {
117	    const card = createCard({ title: 'My Card' });
