126	
127	  it('generates a valid UUID v4 for id', () => {
128	    const card = createCard({ title: 'UUID Test' });
129	    assert.match(card.id, /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i);
130	  });
