150	
151	  it('assigns position 1.0 to the first card in a column', () => {
152	    const card = createCard({ title: 'First Card', column: 'done' });
153	    assert.equal(card.position, 1.0);
154	  });
155	
156	  it('assigns max+1 to subsequent cards in the same column', () => {
157	    const card1 = createCard({ title: 'Card 1', column: 'ready' });
158	    const card2 = createCard({ title: 'Card 2', column: 'ready' });
159	    assert.equal(card2.position, card1.position + 1.0);
160	  });
161	
162	  it('positions are independent per column', () => {
163	    const readyCard = createCard({ title: 'Ready Card', column: 'ready' });
164	    const doneCard  = createCard({ title: 'Done Card',  column: 'done'  });
165	    assert.equal(readyCard.position, 1.0);
166	    assert.equal(doneCard.position,  1.0);
167	  });
168	
169	  it('stores optional fields (assignee, description) when provided', () => {
170	    const card = createCard({ title: 'Full Card', assignee: 'Alice', description: 'Some desc' });
171	    assert.equal(card.assignee,    'Alice');
172	    assert.equal(card.description, 'Some desc');
173	  });
174	
175	  it('card appears in getCards() after creation', () => {
176	    const card  = createCard({ title: 'Visible Card' });
177	    const cards = getCards();
178	    assert.ok(cards.some(c => c.id === card.id));
179	  });
180	});
