182	// ─── updateCard ───────────────────────────────────────────────────────────────
183	describe('updateCard', () => {
184	  let cardId;
185	
186	  beforeEach(() => {
187	    initDb(':memory:');
188	    cardId = createCard({ title: 'Original', assignee: 'Bob' }).id;
189	  });
190	  afterEach(() => closeDb());
191	
192	  it('updates title and returns the updated card', () => {
193	    const card = updateCard(cardId, { title: 'Updated' });
194	    assert.equal(card.title, 'Updated');
