196	
197	  it('partial update does not modify unspecified fields', () => {
198	    updateCard(cardId, { title: 'New Title' });
199	    const card = getCards().find(c => c.id === cardId);
200	    assert.equal(card.assignee, 'Bob');
201	  });
202	
203	  it('can update multiple fields at once', () => {
204	    const card = updateCard(cardId, { title: 'Multi', assignee: 'Alice', description: 'Desc' });
205	    assert.equal(card.title,       'Multi');
206	    assert.equal(card.assignee,    'Alice');
207	    assert.equal(card.description, 'Desc');
