275	// ─── moveCard ─────────────────────────────────────────────────────────────────
276	describe('moveCard', () => {
277	  beforeEach(() => initDb(':memory:'));
278	  afterEach(() => closeDb());
279	
280	  it('moves card to empty column', () => {
281	    const card  = createCard({ title: 'Mover', column: 'ready' });
282	    const moved = moveCard(card.id, 'done', 0);
283	    assert.equal(moved.column,   'done');
284	    assert.equal(moved.position, 1.0);
285	  });
286	
287	  it('moves card to first position in populated column', () => {
288	    const existing = createCard({ title: 'Existing', column: 'done' });
289	    const card     = createCard({ title: 'Mover',    column: 'ready' });
290	    const moved    = moveCard(card.id, 'done', 0);
291	    assert.ok(moved.position < existing.position);
292	  });
293	
294	  it('moves card to last position in populated column', () => {
295	    const existing = createCard({ title: 'Existing', column: 'done' });
296	    const card     = createCard({ title: 'Mover',    column: 'ready' });
297	    const moved    = moveCard(card.id, 'done', 1);
298	    assert.ok(moved.position > existing.position);
299	  });
300	
301	  it('moves card to middle position in column', () => {
302	    const c1   = createCard({ title: 'C1',    column: 'done'  });
303	    const c2   = createCard({ title: 'C2',    column: 'done'  });
304	    const card = createCard({ title: 'Mover', column: 'ready' });
305	    const moved = moveCard(card.id, 'done', 1);
306	    assert.ok(moved.position > c1.position);
307	    assert.ok(moved.position < c2.position);
308	  });
309	
310	  it('returned card reflects updated column and position', () => {
311	    const card  = createCard({ title: 'Mover', column: 'ready' });
312	    const moved = moveCard(card.id, 'in_progress', 0);
313	    assert.equal(moved.column, 'in_progress');
314	    assert.ok(typeof moved.position === 'number');
315	  });
316	
317	  it('moves card within same column to later position', () => {
318	    const c1 = createCard({ title: 'C1', column: 'ready' });
319	    const c2 = createCard({ title: 'C2', column: 'ready' });
320	    const moved = moveCard(c1.id, 'ready', 1);
321	    assert.ok(moved.position > c2.position);
322	  });
323	
324	  it('moves card within same column to earlier position', () => {
325	    const c1 = createCard({ title: 'C1', column: 'ready' });
326	    const c2 = createCard({ title: 'C2', column: 'ready' });
327	    const moved = moveCard(c2.id, 'ready', 0);
328	    assert.ok(moved.position < c1.position);
329	  });
330	
331	  it('renormalizes column when position gap falls below 0.001', () => {
332	    // Create three cards then force a tiny gap between the first two
333	    const cA   = createCard({ title: 'A', column: 'ready' });
334	    const cB   = createCard({ title: 'B', column: 'ready' });
335	    const mover = createCard({ title: 'Mover', column: 'done' });
336	
337	    // Force positions to have a gap of 0.0005 (< 0.001)
338	    const db = getDb();
339	    db.prepare('UPDATE cards SET position = ? WHERE id = ?').run(1.0,    cA.id);
340	    db.prepare('UPDATE cards SET position = ? WHERE id = ?').run(1.0005, cB.id);
341	
342	    // Move Mover between A and B — gap triggers renormalization
343	    const moved = moveCard(mover.id, 'ready', 1);
344	
345	    // After renormalization all positions in 'ready' should be clean integers
346	    const readyCards = db
347	      .prepare('SELECT position FROM cards WHERE "column" = ? ORDER BY position')
348	      .all('ready');
349	    readyCards.forEach((r, i) => {
350	      assert.ok(
351	        Math.abs(r.position - (i + 1.0)) < 0.0001,
352	        `expected position ~${i + 1}, got ${r.position}`,
353	      );
354	    });
355	    assert.equal(moved.column, 'ready');
356	  });
357	
358	  it('throws NotFoundError for a non-existent card id', () => {
359	    assert.throws(() => moveCard('no-such-id', 'ready', 0), NotFoundError);
360	  });
361	
362	  it('negative position value treated as first position', () => {
363	    const c1   = createCard({ title: 'C1',    column: 'done'  });
364	    const card = createCard({ title: 'Mover', column: 'ready' });
365	    const moved = moveCard(card.id, 'done', -5);
366	    assert.ok(moved.position < c1.position);
367	  });
368	
369	  it('position beyond end treated as last position', () => {
370	    const c1   = createCard({ title: 'C1',    column: 'done'  });
371	    const card = createCard({ title: 'Mover', column: 'ready' });
372	    const moved = moveCard(card.id, 'done', 999);
373	    assert.ok(moved.position > c1.position);
374	  });
375	});
